    case['createddate_dt'] = datetime.fromisoformat(case['createddate'].replace("+0000", "+00:00"))
    case['closeddate_dt'] = datetime.fromisoformat(case['closeddate'].replace("+0000", "+00:00"))
    case['handle_time_hours'] = (case['closeddate_dt'] - case['createddate_dt']).total_seconds() / 3600

